import Papa from "papaparse";
import React, { useState } from 'react';
import { db } from '../config/firebase';
import { doc, setDoc, updateDoc, arrayUnion } from 'firebase/firestore';

function Parse() {
  // Stocke les datas parsées du CSV
  const [parsedData, setParsedData] = useState([]);
  const [tableRows, setTableRows] = useState([]);
  const [values, setValues] = useState([]);

  // State for the selected year
  const [selectedYear, setSelectedYear] = useState('2023');

  // Dropdown years options (you can customize this as needed)
  const years = ['2020', '2021', '2022', '2023'];

  async function Send(item) {
    // ... existing code ...
    const ID = String(item.ID);
    const NAMECITY = String(item['CITY NAME']);
    const NAMEROUTE = String(item['ROUTE NAME']);
    const NBRSESSIONSANNUAL = Number(item['NB ROUTE VIEWED']);

    const statisticsRef = doc(db, "Routes", ID, "statistics", `AnnualStats${selectedYear}`);

    await setDoc(statisticsRef, {
      year: selectedYear,
      id: ID,
      nameCity: NAMECITY,
      nameRoute: NAMEROUTE,
      nbrSessionsAnnual: NBRSESSIONSANNUAL
    })
    .then(() => {
      alert("Data Successfully Submitted");
    })
    .catch((error) => {
      console.error("Error adding document: ", error);
    });
  }

  const changeHandler = (event) => {
    // ... existing code ...
    Papa.parse(event.target.files[0], {
      header: true,
      skipEmptyLines: true,
      complete: function (results) {
        // ... existing code ...

        // Iterate through parsed Data and send each item to the Send function
        parsedData.forEach(Send);
      },
    });
  };

  return (
    <div>
      {/* Dropdown for selecting year */}
      <select value={selectedYear} onChange={(e) => setSelectedYear(e.target.value)}>
        {years.map((year) => (
          <option key={year} value={year}>
            {year}
          </option>
        ))}
      </select>

      {/* File Uploader */}
      <input
        type="file"
        name="file"
        onChange={changeHandler}
        accept=".csv"
        style={{ display: "block", margin: "10px auto" }}
      />
      <br />
      <br />

      {/* Existing code to display table */}
      {/* ... */}
    </div>
  );
}

export default Parse;
